mapper.select:
SELECT count(*) FROM TPR504 X LEFT JOIN TPR301 P ON X.FACTORY_CODE = P.FACTORY_CODE AND X.PRODPLAN_DATE = P.PRODPLAN_DATE AND X.PRODPLAN_SEQ = P.PRODPLAN_SEQ AND X.PRODWORK_SEQ = P.PRODWORK_SEQ INNER JOIN TPR601 S ON X.FACTORY_CODE = S.FACTORY_CODE AND X.PRODPLAN_DATE = S.PRODPLAN_DATE AND X.PRODPLAN_SEQ = S.PRODPLAN_SEQ AND X.PRODWORK_SEQ = S.PRODWORK_SEQ AND X.WORK_SEQ = S.WORK_SEQ INNER JOIN TPR605 D ON S.FACTORY_CODE = D.FACTORY_CODE AND S.PRODPLAN_DATE = D.PRODPLAN_DATE AND S.PRODPLAN_SEQ = D.PRODPLAN_SEQ AND S.PRODWORK_SEQ = D.PRODWORK_SEQ AND S.WORK_SEQ = D.WORK_SEQ AND S.PROD_SEQ = D.PROD_SEQ WHERE ISNULL(X.DELETE_FLAG,'') != '1'
AND X.WORKDT_DATE >= REPLACE(#{dateFrom}, '-', '')
AND X.WORKDT_DATE <= REPLACE(#{dateTo}, '-', '')
AND CONVERT(char(8), S.PROD_ETIME, 112) >= REPLACE(#{completeFrom}, '-', '')
AND CONVERT(char(8), S.PROD_ETIME, 112) <= REPLACE(#{completeTo}, '-', '')
AND P.WORKCENTER_CODE = #{workplace}
AND X.EQUIP_SYS_CD = #{equipment}
AND D.QC_CODE = #{defectCode}
